long long solve(vector<vector<long long>> grid, long long k) {
    int m = grid.size();
    if (m == 0) return 0;
    int n = grid[0].size();
    vector<vector<bool>> visited(m, vector<bool>(n, false));
    int directions[4][2] = {{-1, 0}, {1, 0}, {0, -1}, {0, 1}};
    long long count = 0;

    for (int i = 0; i < m; ++i) {
        for (int j = 0; j < n; ++j) {
            if (grid[i][j] > 0 && !visited[i][j]) {
