                long long sum = 0;

                while (!q.empty()) {
                    auto current = q.front();
                    q.pop();
                    int x = current.first;
                    int y = current.second;
                    sum += grid[x][y];

                    for (int d = 0; d < 4; ++d) {
                        int nx = x + directions[d][0];
                        int ny = y + directions[d][1];
                        if (nx >= 0 && nx < m && ny >= 0 && ny < n && grid[nx][ny] > 0 && !visited[nx][ny]) {
                            visited[nx][ny] = true;
                            q.push({nx, ny});
                        }
                    }
                }

                if (sum % k == 0) {
                    count++;
                }
            }
        }
    }

    return count;
}

